117→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
118→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
119→  if (!response.ok || !response.body) {
120→    throw new Error(`Failed to open SSE stream (${response.status})`);
121→  }
122→
123→  const reader = response.body.getReader();
124→  const decoder = new TextDecoder();
125→  const events: T[] = [];
126→  let buffer = "";
127→
128→  const timeout = setTimeout(() => {
129→    void reader.cancel();
130→  }, timeoutMs);
131→
132→  try {
133→    while (true) {
134→      const { value, done } = await reader.read();
135→      if (done) {
136→        break;
137→      }
138→
139→      buffer += decoder.decode(value, { stream: true });
140→      const segments = buffer.split("\n\n");
141→      buffer = segments.pop() ?? "";
142→
143→      for (const segment of segments) {
144→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
145→        if (!dataLine) {
146→          continue;
147→        }
148→
149→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
150→        events.push(event);
151→
152→        if (event.type === "error") {
153→          const errorText = (event as { error?: string }).error;
154→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
155→        }
156→
157→        if (event.type === "done") {
158→          return events;
159→        }
160→      }
161→    }
162→  } finally {
163→    clearTimeout(timeout);
164→    reader.releaseLock();
165→  }
166→
167→  return events;
168→}
