171→  const response = await fetch(url, init);
172→  if (!response.ok) {
173→    const body = await response.text();
174→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
175→  }
176→
177→  return (await response.json()) as T;
178→}
