191→      if (response.ok) {
192→        return;
193→      }
194→    } catch {
195→      // Keep polling.
196→    }
197→
198→    await Bun.sleep(200);
199→  }
200→
201→  throw new Error(`Timed out waiting for smoke server health at ${url}/healthz`);
202→}
