204→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
205→  return await Promise.race([
206→    callback(),
207→    new Promise<T>((_, reject) => {
208→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
209→    }),
210→  ]);
