254→// ---------------------------------------------------------------------------
255→
256→type HookEntry = { type: string; command?: string; prompt?: string };
257→type SettingsHookGroup = { matcher?: string; hooks: HookEntry[] };
258→
259→async function setupClaudeHooks(gitRoot: string): Promise<void> {
260→  const claudeDir = join(gitRoot, ".claude");
261→  if (!existsSync(claudeDir)) mkdirSync(claudeDir, { recursive: true });
262→
263→  const settingsPath = join(claudeDir, "settings.json");
264→  const file = Bun.file(settingsPath);
