266→
267→  if (await file.exists()) {
268→    try {
269→      settings = await file.json();
270→    } catch {
271→      // Corrupted — start fresh
272→    }
273→  }
274→
275→  const hooks = (settings.hooks ?? {}) as Record<string, SettingsHookGroup[]>;
276→  let added = 0;
277→
278→  for (const [event, hookDefs] of Object.entries(BRAIN_HOOKS)) {
279→    hooks[event] ??= [];
280→
281→    const hasBrain = hooks[event].some((group) =>
282→      group.hooks?.some(
283→        (h) => h.command?.startsWith("brain ") || h.prompt?.includes("Brain MCP"),
284→      ),
285→    );
286→
287→    if (!hasBrain) {
288→      hooks[event].push({ hooks: hookDefs as HookEntry[] });
289→      added++;
290→    }
291→  }
292→
293→  settings.hooks = hooks;
294→  await Bun.write(settingsPath, JSON.stringify(settings, null, 2) + "\n");
