314→  const brainBlock = `${MARKER_START}\n${BRAIN_CLAUDE_MD}\n${MARKER_END}`;
315→
316→  const startIdx = content.indexOf(MARKER_START);
317→  const endIdx = content.indexOf(MARKER_END);
318→
319→  if (startIdx !== -1 && endIdx !== -1) {
320→    content = content.slice(0, startIdx) + brainBlock + content.slice(endIdx + MARKER_END.length);
321→  } else {
322→    const separator = content.length > 0 && !content.endsWith("\n\n") ? "\n\n" : "";
323→    content = content + separator + brainBlock + "\n";
324→  }
325→
326→  await Bun.write(claudeMdPath, content);
327→  console.log("✓ CLAUDE.md: Brain plugin instructions added");
328→}
