# Plan: Make Brain CLI `init` Command E2E Testable

## Design Decisions

### 1. Test location: `tests/unit/cli-init.test.ts`
These are pure file-operation tests with no server dependency. They belong in `tests/unit/` so they run with `bun test tests/unit/` (the `"test"` script). This follows the existing convention: unit tests are deterministic, no external services.

### 2. Temp git repo: inline `createTempGitRepo()` helper inside the test file
No shared utility needed -- only this test file uses temp git repos. The helper uses `mkdtempSync` + `git init` in `beforeEach`, and `rmSync(recursive)` in `afterEach`. Each test gets a fresh repo.

### 3. Export strategy: named exports of each step function from `init.ts`
Export `setupMcpJson`, `setupClaudeHooks`, `setupClaudeMd`, `setupCommands` as named exports. `installGitHooks` is already exported. Do NOT create a structured `initSteps` object -- that adds indirection for no benefit. Keep `setupAuth` private since it requires a running server and browser.

Also export `MARKER_START` and `MARKER_END` constants so tests can verify marker-based idempotency without duplicating magic strings.

### 4. Do NOT test `runInit()` orchestration
`runInit()` calls `setupAuth()` which requires a live server + browser OAuth flow. Testing the full flow would require mocking the auth step, which adds complexity without coverage value. The individual step tests cover all the file operations.

---

## Implementation Steps

### Step 1: Export step functions from `cli/commands/init.ts`

Add named exports to the 4 currently-private async functions and the 2 marker constants:

```typescript
// Before (private):
async function setupMcpJson(gitRoot: string): Promise<void> { ... }

// After (exported):
export async function setupMcpJson(gitRoot: string): Promise<void> { ... }
```

Functions to export:
- `setupMcpJson(gitRoot: string): Promise<void>`
- `setupClaudeHooks(gitRoot: string): Promise<void>`
- `setupClaudeMd(gitRoot: string): Promise<void>`
- `setupCommands(gitRoot: string): Promise<void>`
- `MARKER_START` (const)
- `MARKER_END` (const)

`installGitHooks(gitRoot?: string): void` is already exported. No changes needed.

**Do NOT export:** `setupAuth`, `generatePkce`, `base64url`, `HookEntry`, `SettingsHookGroup` -- these are auth internals.

### Step 2: Create `tests/unit/cli-init.test.ts`

#### Test infrastructure (top of file)

```typescript
import { describe, expect, it, beforeEach, afterEach } from "bun:test";
import { mkdtempSync, rmSync, existsSync, readFileSync, statSync } from "node:fs";
import { join } from "node:path";
import { tmpdir } from "node:os";
import { execSync } from "node:child_process";
import {
  setupMcpJson,
  setupClaudeHooks,
  setupClaudeMd,
  setupCommands,
  installGitHooks,
  MARKER_START,
  MARKER_END,
} from "../../cli/commands/init";
import { BRAIN_HOOKS, BRAIN_CLAUDE_MD, BRAIN_COMMANDS } from "../../cli/commands/init-content";

let gitRoot: string;

beforeEach(() => {
  gitRoot = mkdtempSync(join(tmpdir(), "brain-init-test-"));
  execSync("git init", { cwd: gitRoot, stdio: "ignore" });
});

afterEach(() => {
  rmSync(gitRoot, { recursive: true, force: true });
});
```

#### Test suite: `setupMcpJson`

```typescript
describe("setupMcpJson", () => {
  it("creates .mcp.json with brain server entry on fresh repo", async () => {
    await setupMcpJson(gitRoot);

    const mcp = JSON.parse(readFileSync(join(gitRoot, ".mcp.json"), "utf8"));
    expect(mcp.mcpServers.brain).toEqual({ command: "brain", args: ["mcp"] });
  });

  it("preserves existing MCP servers and adds brain", async () => {
    // Pre-seed with an existing server
    await Bun.write(
      join(gitRoot, ".mcp.json"),
      JSON.stringify({ mcpServers: { other: { command: "other-tool" } } }, null, 2),
    );

    await setupMcpJson(gitRoot);

    const mcp = JSON.parse(readFileSync(join(gitRoot, ".mcp.json"), "utf8"));
    expect(mcp.mcpServers.other).toEqual({ command: "other-tool" });
    expect(mcp.mcpServers.brain).toEqual({ command: "brain", args: ["mcp"] });
  });

  it("is idempotent -- running twice produces same result", async () => {
    await setupMcpJson(gitRoot);
    await setupMcpJson(gitRoot);

    const mcp = JSON.parse(readFileSync(join(gitRoot, ".mcp.json"), "utf8"));
    expect(mcp.mcpServers.brain).toEqual({ command: "brain", args: ["mcp"] });
    // Should not have duplicate keys (JSON.parse would overwrite, so verify structure)
    expect(Object.keys(mcp.mcpServers)).toEqual(["brain"]);
  });

  it("overwrites corrupted .mcp.json", async () => {
    await Bun.write(join(gitRoot, ".mcp.json"), "not valid json{{{");

    await setupMcpJson(gitRoot);

    const mcp = JSON.parse(readFileSync(join(gitRoot, ".mcp.json"), "utf8"));
    expect(mcp.mcpServers.brain).toEqual({ command: "brain", args: ["mcp"] });
  });
});
```

#### Test suite: `setupClaudeHooks`

```typescript
describe("setupClaudeHooks", () => {
  it("creates .claude/settings.json with all hook events", async () => {
    await setupClaudeHooks(gitRoot);

    const settings = JSON.parse(readFileSync(join(gitRoot, ".claude", "settings.json"), "utf8"));
    const hookEvents = Object.keys(settings.hooks);

    // Should have all events from BRAIN_HOOKS
    for (const event of Object.keys(BRAIN_HOOKS)) {
      expect(hookEvents).toContain(event);
    }
  });

  it("preserves existing hooks from other tools", async () => {
    const existingSettings = {
      hooks: {
        PreToolUse: [{ hooks: [{ type: "command", command: "eslint --fix" }] }],
      },
      someOtherSetting: true,
    };
    const claudeDir = join(gitRoot, ".claude");
    execSync(`mkdir -p "${claudeDir}"`);
    await Bun.write(join(claudeDir, "settings.json"), JSON.stringify(existingSettings, null, 2));

    await setupClaudeHooks(gitRoot);

    const settings = JSON.parse(readFileSync(join(claudeDir, "settings.json"), "utf8"));
    // Existing eslint hook preserved
    expect(settings.hooks.PreToolUse[0].hooks[0].command).toBe("eslint --fix");
    // Brain hook added after
    expect(settings.hooks.PreToolUse.length).toBe(2);
    expect(settings.someOtherSetting).toBe(true);
  });

  it("does not duplicate brain hooks on second run", async () => {
    await setupClaudeHooks(gitRoot);
    await setupClaudeHooks(gitRoot);

    const settings = JSON.parse(readFileSync(join(gitRoot, ".claude", "settings.json"), "utf8"));
    // Each event should have exactly 1 hook group (the brain one)
    for (const event of Object.keys(BRAIN_HOOKS)) {
      expect(settings.hooks[event].length).toBe(1);
    }
  });

  it("creates .claude directory if missing", async () => {
    expect(existsSync(join(gitRoot, ".claude"))).toBe(false);
    await setupClaudeHooks(gitRoot);
    expect(existsSync(join(gitRoot, ".claude", "settings.json"))).toBe(true);
  });
});
```

#### Test suite: `setupClaudeMd`

```typescript
describe("setupClaudeMd", () => {
  it("creates CLAUDE.md with brain block on fresh repo", async () => {
    await setupClaudeMd(gitRoot);

    const content = readFileSync(join(gitRoot, "CLAUDE.md"), "utf8");
    expect(content).toContain(MARKER_START);
    expect(content).toContain(MARKER_END);
    expect(content).toContain(BRAIN_CLAUDE_MD);
  });

  it("appends brain block to existing CLAUDE.md content", async () => {
    await Bun.write(join(gitRoot, "CLAUDE.md"), "# My Project\n\nExisting instructions.\n");

    await setupClaudeMd(gitRoot);

    const content = readFileSync(join(gitRoot, "CLAUDE.md"), "utf8");
    expect(content).toStartWith("# My Project\n\nExisting instructions.\n");
    expect(content).toContain(MARKER_START);
    expect(content).toContain(BRAIN_CLAUDE_MD);
  });

  it("replaces existing brain block on second run (idempotent update)", async () => {
    await setupClaudeMd(gitRoot);
    const firstContent = readFileSync(join(gitRoot, "CLAUDE.md"), "utf8");

    await setupClaudeMd(gitRoot);
    const secondContent = readFileSync(join(gitRoot, "CLAUDE.md"), "utf8");

    expect(secondContent).toBe(firstContent);
    // Verify only one brain block exists
    const startCount = secondContent.split(MARKER_START).length - 1;
    expect(startCount).toBe(1);
  });

  it("preserves content before and after brain block on update", async () => {
    const before = "# Project\n\nBefore brain.\n\n";
    const after = "\n\n# Other Section\n\nAfter brain.\n";
    await Bun.write(
      join(gitRoot, "CLAUDE.md"),
      before + MARKER_START + "\nold content\n" + MARKER_END + after,
    );

    await setupClaudeMd(gitRoot);

    const content = readFileSync(join(gitRoot, "CLAUDE.md"), "utf8");
    expect(content).toStartWith(before);
    expect(content).toContain(BRAIN_CLAUDE_MD);
    expect(content).toEndWith(after);
  });
});
```

