#### Test suite: `installGitHooks`

```typescript
describe("installGitHooks", () => {
  it("creates pre-commit hook with correct content and permissions", () => {
    installGitHooks(gitRoot);

    const hookPath = join(gitRoot, ".git", "hooks", "pre-commit");
    expect(existsSync(hookPath)).toBe(true);

    const content = readFileSync(hookPath, "utf8");
    expect(content).toContain("#!/bin/sh");
    expect(content).toContain("brain check-commit");

    const mode = statSync(hookPath).mode;
    expect(mode & 0o755).toBe(0o755);
  });

  it("does not overwrite existing pre-commit hook", () => {
    const hookPath = join(gitRoot, ".git", "hooks", "pre-commit");
    execSync(`mkdir -p "${join(gitRoot, ".git", "hooks")}"`);
    await Bun.write(hookPath, "#!/bin/sh\neslint .\n");

    installGitHooks(gitRoot);

    const content = readFileSync(hookPath, "utf8");
    expect(content).toContain("eslint");
    expect(content).not.toContain("brain check-commit");
  });

  it("removes legacy Brain post-commit hook", () => {
    const hooksDir = join(gitRoot, ".git", "hooks");
    execSync(`mkdir -p "${hooksDir}"`);
    const postCommitPath = join(hooksDir, "post-commit");
    // Write a legacy brain post-commit hook
    Bun.writeSync(
      Bun.openSync(postCommitPath, "w"),
      "#!/bin/sh\n# Brain post-commit hook\nbrain log-commit\n",
    );

    installGitHooks(gitRoot);

    expect(existsSync(postCommitPath)).toBe(false);
  });

  it("preserves non-Brain post-commit hooks", () => {
    const hooksDir = join(gitRoot, ".git", "hooks");
    execSync(`mkdir -p "${hooksDir}"`);
    const postCommitPath = join(hooksDir, "post-commit");
    Bun.writeSync(
      Bun.openSync(postCommitPath, "w"),
      "#!/bin/sh\nnotify-deploy\n",
    );

    installGitHooks(gitRoot);

    expect(existsSync(postCommitPath)).toBe(true);
    const content = readFileSync(postCommitPath, "utf8");
    expect(content).toContain("notify-deploy");
  });

  it("creates .git/hooks/ directory if missing", () => {
    rmSync(join(gitRoot, ".git", "hooks"), { recursive: true, force: true });

    installGitHooks(gitRoot);

    expect(existsSync(join(gitRoot, ".git", "hooks", "pre-commit"))).toBe(true);
  });
});
