 49→// ---------------------------------------------------------------------------
 50→// Step 1: Auth (OAuth 2.1 PKCE)
 51→// ---------------------------------------------------------------------------
 52→
 53→const DEFAULT_SCOPES = "graph:read graph:reason decision:write task:write observation:write question:write session:write offline_access";
 54→
 55→function base64url(buf: Buffer): string {
 56→  return buf.toString("base64url");
 57→}
 58→
 59→function generatePkce(): { verifier: string; challenge: string } {
 60→  const verifier = base64url(randomBytes(32));
 61→  const challenge = base64url(createHash("sha256").update(verifier).digest());
 62→  return { verifier, challenge };
 63→}
 64→
 65→async function setupAuth(serverUrl: string, workspaceId: string, gitRoot: string): Promise<void> {
 66→  const global = await loadGlobalConfig();
 67→  const existing = global?.repos[gitRoot];
 68→  if (existing && existing.workspace === workspaceId && existing.access_token) {
 69→    console.log(`✓ Auth: already configured for ${gitRoot}`);
 70→    return;
 71→  }
 72→
 73→  // 1. Verify workspace exists
 74→  try {
 75→    await BrainHttpClient.listProjects(serverUrl, workspaceId);
 76→  } catch {
 77→    console.error(`Workspace ${workspaceId} not found on ${serverUrl}`);
 78→    process.exit(1);
 79→  }
 80→
 81→  // 2. Dynamic Client Registration
 82→  const dcrRes = await fetch(`${serverUrl}/api/auth/oauth2/register`, {
 83→    method: "POST",
 84→    headers: { "Content-Type": "application/json" },
 85→    body: JSON.stringify({
 86→      client_name: `brain-cli-${workspaceId.slice(0, 8)}`,
 87→      redirect_uris: ["http://127.0.0.1/callback"],
 88→      grant_types: ["authorization_code", "refresh_token"],
 89→      response_types: ["code"],
 90→      token_endpoint_auth_method: "none",
 91→    }),
 92→  });
 93→  if (!dcrRes.ok) {
 94→    throw new Error(`Client registration failed: ${dcrRes.status} ${await dcrRes.text()}`);
 95→  }
 96→  const { client_id } = await dcrRes.json() as { client_id: string };
 97→
 98→  // 3. PKCE
 99→  const pkce = generatePkce();
100→  const state = base64url(randomBytes(16));
101→
102→  // 4. Start local callback server
103→  const { promise: codePromise, resolve: resolveCode, reject: rejectCode } = Promise.withResolvers<string>();
104→
105→  const callbackServer = Bun.serve({
106→    port: 0,
107→    hostname: "127.0.0.1",
108→    routes: {
109→      "/callback": (request) => {
110→        const url = new URL(request.url);
111→        const code = url.searchParams.get("code");
112→        const returnedState = url.searchParams.get("state");
113→        const error = url.searchParams.get("error");
114→
115→        if (error) {
116→          rejectCode(new Error(`OAuth error: ${error}`));
117→          return new Response("<html><body><h1>Authentication failed</h1><p>You can close this tab.</p></body></html>", {
118→            headers: { "Content-Type": "text/html" },
119→          });
120→        }
121→        if (returnedState !== state) {
122→          rejectCode(new Error("state mismatch"));
123→          return new Response("<html><body><h1>State mismatch</h1></body></html>", {
124→            headers: { "Content-Type": "text/html" },
125→          });
126→        }
127→        if (!code) {
128→          rejectCode(new Error("no code returned"));
129→          return new Response("<html><body><h1>No authorization code</h1></body></html>", {
130→            headers: { "Content-Type": "text/html" },
131→          });
132→        }
133→
134→        resolveCode(code);
135→        return new Response("<html><body><h1>Authenticated!</h1><p>You can close this tab and return to the terminal.</p></body></html>", {
136→          headers: { "Content-Type": "text/html" },
137→        });
138→      },
139→    },
140→  });
141→
142→  const redirectUri = `http://127.0.0.1:${callbackServer.port}/callback`;
143→
144→  // Update redirect_uris with actual port (re-register)
145→  const dcrUpdateRes = await fetch(`${serverUrl}/api/auth/oauth2/register`, {
146→    method: "POST",
147→    headers: { "Content-Type": "application/json" },
148→    body: JSON.stringify({
149→      client_name: `brain-cli-${workspaceId.slice(0, 8)}`,
150→      redirect_uris: [redirectUri],
151→      grant_types: ["authorization_code", "refresh_token"],
152→      response_types: ["code"],
153→      token_endpoint_auth_method: "none",
154→    }),
155→  });
156→  if (!dcrUpdateRes.ok) {
157→    callbackServer.stop();
158→    throw new Error(`Client re-registration failed: ${dcrUpdateRes.status} ${await dcrUpdateRes.text()}`);
159→  }
160→  const dcrUpdate = await dcrUpdateRes.json() as { client_id: string };
161→  const actualClientId = dcrUpdate.client_id;
162→
163→  // 5. Open browser
164→  const authUrl = new URL(`${serverUrl}/api/auth/oauth2/authorize`);
165→  authUrl.searchParams.set("client_id", actualClientId);
166→  authUrl.searchParams.set("redirect_uri", redirectUri);
167→  authUrl.searchParams.set("response_type", "code");
168→  authUrl.searchParams.set("scope", DEFAULT_SCOPES);
169→  authUrl.searchParams.set("code_challenge", pkce.challenge);
170→  authUrl.searchParams.set("code_challenge_method", "S256");
171→  authUrl.searchParams.set("state", state);
172→  // Pass resource so better-auth issues a JWT access token (not opaque)
173→  authUrl.searchParams.set("resource", serverUrl);
174→
175→  console.log("Opening browser for authentication...");
176→  console.log(`If the browser doesn't open, visit: ${authUrl.toString()}\n`);
177→
178→  const openCmd = process.platform === "darwin" ? "open" : process.platform === "win32" ? "start" : "xdg-open";
179→  Bun.spawn([openCmd, authUrl.toString()], { stdout: "ignore", stderr: "ignore" });
180→
181→  // 6. Wait for callback
182→  let code: string;
