  let added = 0;

  for (const [event, hookDefs] of Object.entries(BRAIN_HOOKS)) {
    hooks[event] ??= [];

    const hasBrain = hooks[event].some((group) =>
      group.hooks?.some(
        (h) => h.command?.startsWith("brain ") || h.prompt?.includes("Brain MCP"),
      ),
