    if (!hasBrain) {
      hooks[event].push({ hooks: hookDefs as HookEntry[] });
      added++;
    }
  }

  settings.hooks = hooks;
  await Bun.write(settingsPath, JSON.stringify(settings, null, 2) + "\n");
