  // Step 4: CLAUDE.md
  await setupClaudeMd(gitRoot);

  // Step 5: Commands
  await setupCommands(gitRoot);

  // Step 6: Git hooks
  installGitHooks(gitRoot);

  console.log(`\nDone. Restart Claude Code to activate.`);
}

