 30→  if (!res.ok) {
 31→    throw new Error(`Sign up failed: ${res.status} ${await res.text()}`);
 32→  }
 33→
 34→  // Sign-up returns user + session in JSON body
 35→  const data = await res.json() as { user: { id: string }; token: string };
 36→
 37→  // Also extract session cookie for subsequent requests
 38→  const cookies = res.headers.getSetCookie();
 39→  const sessionCookie = cookies.find(c => c.startsWith("better-auth.session_token="));
 40→  const sessionToken = sessionCookie
 41→    ? decodeURIComponent(sessionCookie.split("=")[1].split(";")[0])
 42→    : data.token;
 43→
 44→  return {
 45→    userId: data.user.id,
 46→    sessionToken,
 47→    headers: { Cookie: `better-auth.session_token=${sessionToken}` },
 48→  };
 49→}
