345→  const sessionCookie = cookies.find(c => c.startsWith("better-auth.session_token="));
346→  const sessionToken = sessionCookie
347→    ? decodeURIComponent(sessionCookie.split("=")[1].split(";")[0])
348→    : data.token;
349→
350→  return {
351→    userId: data.user.id,
352→    sessionToken,
353→    headers: { Cookie: `better-auth.session_token=${sessionToken}` },
354→  };
355→}
